solution_code:
#include <stdio.h>
#include <pthread.h>

int counter = 0;
pthread_mutex_t mtx = PTHREAD_MUTEX_INITIALIZER;

int main(void) {
    pthread_mutex_lock(&mtx);
    printf("Locked\n");
    counter++;
    printf("counter = %d\n", counter);
    pthread_mutex_unlock(&mtx);
    printf("Unlocked\n");
    pthread_mutex_destroy(&mtx);
    return 0;
}

starter_code_stages:
#include <stdio.h>
#include <pthread.h>

// ★ Stage 0 — Exemple complet
int counter = 0;
pthread_mutex_t mtx = PTHREAD_MUTEX_INITIALIZER; // ★ init statique, pas besoin de pthread_mutex_init

int main(void) {
    pthread_mutex_lock(&mtx);    // ★ acquérir le verrou
    printf("Locked\n");
    counter++;
    printf("counter = %d\n", counter);
    pthread_mutex_unlock(&mtx);  // ★ libérer le verrou
    printf("Unlocked\n");
    pthread_mutex_destroy(&mtx); // ★ libérer les ressources
    return 0;
}

